use crate::types::{DecideInput, DecideOutput};

const LT: &str = "LT";
const EQ: &str = "EQ";
const GT: &str = "GT";

fn realcompare(a: f64, b: f64) -> &'static str {
    let diff = (a - b).abs();
    let abs_a = a.abs();
    let abs_b = b.abs();
    let scale = abs_a.max(abs_b);
    let tolerance = if scale == 0.0 {
        1e-12
    } else {
        (scale * 1e-6).max(1e-12)
    };
    if diff <= tolerance {
        EQ
    } else if a < b {
        LT
    } else {
        GT
    }
}

fn real_lt(a: f64, b: f64) -> bool {
    realcompare(a, b) == LT
}

fn real_gt(a: f64, b: f64) -> bool {
    realcompare(a, b) == GT
}

fn real_le(a: f64, b: f64) -> bool {
    realcompare(a, b) != GT
}

fn real_ge(a: f64, b: f64) -> bool {
    realcompare(a, b) != LT
}

#[derive(Clone, Copy)]
struct Point {
    x: f64,
    y: f64,
}

fn points(input: &DecideInput) -> Vec<Point> {
    input
        .x
        .iter()
        .zip(&input.y)
        .map(|(&x, &y)| Point { x, y })
        .collect()
}

fn distance(a: Point, b: Point) -> f64 {
    ((a.x - b.x).powi(2) + (a.y - b.y).powi(2)).sqrt()
}

fn triangle_area(a: Point, b: Point, c: Point) -> f64 {
    ((a.x * (b.y - c.y)) + (b.x * (c.y - a.y)) + (c.x * (a.y - b.y))).abs() / 2.0
}

fn angle(a: Point, vertex: Point, c: Point) -> Option<f64> {
    let v1 = (a.x - vertex.x, a.y - vertex.y);
    let v2 = (c.x - vertex.x, c.y - vertex.y);
    let norm1 = (v1.0.powi(2) + v1.1.powi(2)).sqrt();
    let norm2 = (v2.0.powi(2) + v2.1.powi(2)).sqrt();
    if realcompare(norm1, 0.0) == EQ || realcompare(norm2, 0.0) == EQ {
        return None;
    }
    let mut dot = v1.0 * v2.0 + v1.1 * v2.1;
    let denom = norm1 * norm2;
    if realcompare(denom, 0.0) == EQ {
        return None;
    }
    let mut cos_theta = dot / denom;
    if cos_theta > 1.0 {
        cos_theta = 1.0;
    } else if cos_theta < -1.0 {
        cos_theta = -1.0;
    }
    Some(cos_theta.acos())
}

fn distance_to_line(start: Point, end: Point, point: Point) -> f64 {
    let dx = end.x - start.x;
    let dy = end.y - start.y;
    if realcompare(dx.abs() + dy.abs(), 0.0) == EQ {
        return distance(start, point);
    }
    ((dy * point.x - dx * point.y + end.x * start.y - end.y * start.x).abs())
        / (dx.powi(2) + dy.powi(2)).sqrt()
}

fn minimal_enclosing_radius(a: Point, b: Point, c: Point) -> f64 {
    let mut sides = [distance(a, b), distance(b, c), distance(c, a)];
    sides.sort_by(|u, v| u.partial_cmp(v).unwrap());
    let area = triangle_area(a, b, c);
    if realcompare(area, 0.0) == EQ {
        return sides[2] / 2.0;
    }
    let largest_sq = sides[2] * sides[2];
    let other_sq_sum = sides[0] * sides[0] + sides[1] * sides[1];
    if real_ge(largest_sq, other_sq_sum) {
        sides[2] / 2.0
    } else {
        (sides[0] * sides[1] * sides[2]) / (4.0 * area)
    }
}

fn quadrant(point: Point) -> u8 {
    let x_cmp = realcompare(point.x, 0.0);
    let y_cmp = realcompare(point.y, 0.0);
    if (x_cmp == GT || x_cmp == EQ) && (y_cmp == GT || y_cmp == EQ) {
        return 1;
    }
    if x_cmp == LT && (y_cmp == GT || y_cmp == EQ) {
        return 2;
    }
    if (y_cmp == LT) && (x_cmp == LT || x_cmp == EQ) {
        return 3;
    }
    4
}

fn lic1(points: &[Point], length1: f64) -> bool {
    points
        .windows(2)
        .any(|pair| real_gt(distance(pair[0], pair[1]), length1))
}

fn lic2(points: &[Point], radius1: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    points
        .windows(3)
        .any(|triple| real_gt(minimal_enclosing_radius(triple[0], triple[1], triple[2]), radius1))
}

fn lic3(points: &[Point], epsilon: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    let lower = std::f64::consts::PI - epsilon;
    let upper = std::f64::consts::PI + epsilon;
    points.windows(3).any(|triple| {
        if let Some(angle_value) = angle(triple[0], triple[1], triple[2]) {
            real_lt(angle_value, lower) || real_gt(angle_value, upper)
        } else {
            false
        }
    })
}

fn lic4(points: &[Point], area1: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    points
        .windows(3)
        .any(|triple| real_gt(triangle_area(triple[0], triple[1], triple[2]), area1))
}

fn lic5(points: &[Point], q_pts: usize, quads: usize) -> bool {
    if q_pts > points.len() {
        return false;
    }
    for window in points.windows(q_pts) {
        let mut seen = [false; 4];
        for &p in window {
            let idx = (quadrant(p) as usize).saturating_sub(1);
            if idx < 4 {
                seen[idx] = true;
            }
        }
        if seen.iter().filter(|&&v| v).count() > quads {
            return true;
        }
    }
    false
}

fn lic6(points: &[Point]) -> bool {
    points
        .windows(2)
        .any(|pair| real_lt(pair[1].x - pair[0].x, 0.0))
}

fn lic7(points: &[Point], n_pts: usize, dist: f64) -> bool {
    if points.len() < 3 || n_pts > points.len() {
        return false;
    }
    for window in points.windows(n_pts) {
        let first = window[0];
        let last = window[n_pts - 1];
        if realcompare(distance(first, last), 0.0) == EQ {
            for &point in window {
                if real_gt(distance(first, point), dist) {
                    return true;
                }
            }
        } else {
            for &point in window {
                if real_gt(distance_to_line(first, last, point), dist) {
                    return true;
                }
            }
        }
    }
    false
}

fn lic8(points: &[Point], length1: f64, k_pts: usize) -> bool {
    if points.len() < 3 {
        return false;
    }
    let separation = k_pts + 1;
    for i in 0..points.len() - separation {
        if real_gt(distance(points[i], points[i + separation]), length1) {
            return true;
        }
    }
    false
}

fn lic9(points: &[Point], radius1: f64, a_pts: usize, b_pts: usize) -> bool {
    if points.len() < 5 {
        return false;
    }
    let separation1 = a_pts + 1;
    let separation2 = b_pts + 1;
    let total = separation1 + separation2;
    if total >= points.len() {
        return false;
    }
    for i in 0..=points.len() - total - 1 {
        let j = i + separation1;
        let k = j + separation2;
        if real_gt(minimal_enclosing_radius(points[i], points[j], points[k]), radius1) {
            return true;
        }
    }
    false
}

fn lic10(points: &[Point], epsilon: f64, c_pts: usize, d_pts: usize) -> bool {
    if points.len() < 5 {
        return false;
    }
    let separation1 = c_pts + 1;
    let separation2 = d_pts + 1;
    let total = separation1 + separation2;
    if total >= points.len() {
        return false;
    }
    let lower = std::f64::consts::PI - epsilon;
    let upper = std::f64::consts::PI + epsilon;
    for i in 0..=points.len() - total - 1 {
        let j = i + separation1;
        let k = j + separation2;
        if let Some(angle_value) = angle(points[i], points[j], points[k]) {
            if real_lt(angle_value, lower) || real_gt(angle_value, upper) {
                return true;
            }
        }
    }
    false
}

fn lic11(points: &[Point], area1: f64, e_pts: usize, f_pts: usize) -> bool {
    if points.len() < 5 {
        return false;
    }
    let separation1 = e_pts + 1;
    let separation2 = f_pts + 1;
    let total = separation1 + separation2;
    if total >= points.len() {
        return false;
    }
    for i in 0..=points.len() - total - 1 {
        let j = i + separation1;
        let k = j + separation2;
        if real_gt(triangle_area(points[i], points[j], points[k]), area1) {
            return true;
        }
    }
    false
}

fn lic12(points: &[Point], g_pts: usize) -> bool {
    if points.len() < 3 {
        return false;
    }
    let separation = g_pts + 1;
    for i in 0..points.len() - separation {
        if real_lt(points[i + separation].x - points[i].x, 0.0) {
            return true;
        }
    }
    false
}

fn lic13(points: &[Point], length1: f64, length2: f64, k_pts: usize) -> bool {
    if points.len() < 3 {
        return false;
    }
    let separation = k_pts + 1;
    let mut found_gt = false;
    let mut found_lt = false;
    for i in 0..points.len() - separation {
        let d = distance(points[i], points[i + separation]);
        if !found_gt && real_gt(d, length1) {
            found_gt = true;
        }
        if !found_lt && real_lt(d, length2) {
            found_lt = true;
        }
        if found_gt && found_lt {
            return true;
        }
    }
    false
}

fn lic14(
    points: &[Point],
    radius1: f64,
    radius2: f64,
    a_pts: usize,
    b_pts: usize,
) -> bool {
    if points.len() < 5 {
        return false;
    }
    let separation1 = a_pts + 1;
    let separation2 = b_pts + 1;
    let total = separation1 + separation2;
    if total >= points.len() {
        return false;
    }
    let mut exists_gt = false;
    let mut exists_le = false;
    for i in 0..=points.len() - total - 1 {
        let j = i + separation1;
        let k = j + separation2;
        let radius = minimal_enclosing_radius(points[i], points[j], points[k]);
        if !exists_gt && real_gt(radius, radius1) {
            exists_gt = true;
        }
        if !exists_le && real_le(radius, radius2) {
            exists_le = true;
        }
        if exists_gt && exists_le {
            return true;
        }
    }
    false
}

fn lic15(
    points: &[Point],
    area1: f64,
    area2: f64,
    e_pts: usize,
    f_pts: usize,
) -> bool {
    if points.len() < 5 {
        return false;
    }
    let separation1 = e_pts + 1;
    let separation2 = f_pts + 1;
    let total = separation1 + separation2;
    if total >= points.len() {
        return false;
    }
    let mut exists_gt = false;
    let mut exists_lt = false;
    for i in 0..=points.len() - total - 1 {
        let j = i + separation1;
        let k = j + separation2;
        let area = triangle_area(points[i], points[j], points[k]);
        if !exists_gt && real_gt(area, area1) {
            exists_gt = true;
        }
        if !exists_lt && real_lt(area, area2) {
            exists_lt = true;
        }
        if exists_gt && exists_lt {
            return true;
        }
    }
    false
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let pts = points(input);
    let params = &input.parameters;

    let mut cmv = [false; 15];
    cmv[0] = lic1(&pts, params.length1);
    cmv[1] = lic2(&pts, params.radius1);
    cmv[2] = lic3(&pts, params.epsilon);
    cmv[3] = lic4(&pts, params.area1);
    cmv[4] = lic5(&pts, params.q_pts, params.quads);
    cmv[5] = lic6(&pts);
    cmv[6] = lic7(&pts, params.n_pts, params.dist);
    cmv[7] = lic8(&pts, params.length1, params.k_pts);
    cmv[8] = lic9(&pts, params.radius1, params.a_pts, params.b_pts);
    cmv[9] = lic10(&pts, params.epsilon, params.c_pts, params.d_pts);
    cmv[10] = lic11(&pts, params.area1, params.e_pts, params.f_pts);
    cmv[11] = lic12(&pts, params.g_pts);
    cmv[12] = lic13(&pts, params.length1, params.length2, params.k_pts);
    cmv[13] = lic14(&pts, params.radius1, params.radius2, params.a_pts, params.b_pts);
    cmv[14] = lic15(&pts, params.area1, params.area2, params.e_pts, params.f_pts);

    let mut pum = [[false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                continue;
            }
            match input.lcm[i][j].as_str() {
                "NOTUSED" => pum[i][j] = true,
                "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                "ORR" => pum[i][j] = cmv[i] || cmv[j],
                _ => pum[i][j] = false,
            }
        }
    }

    let mut fuv = [false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
            continue;
        }
        fuv[i] = pum[i].iter().all(|&v| v);
    }

    let launch = fuv.iter().all(|&v| v);

    DecideOutput::from_fixed(cmv, pum, fuv, launch)
}
